	/// <summary>
	/// General terms for describing landscapes.
	/// </summary>
	public class categoryOfLandRegion : S100FC.EnumerationAttribute
	{
		[JsonIgnore]
		public override string S100FC_code => nameof(categoryOfLandRegion);
		[JsonIgnore]
		public override string S100FC_name => "Category of Land Region";
		public static listedValue[] listedValues => [
				new listedValue("Fen", "A type of bog, especially a low-lying area, wholly or partly covered with water and dominated by grass-like plants, grasses, sedges and reeds.",1),
				new listedValue("Marsh", "An area of wet, often spongy ground that is subject to frequent flooding or tidal inundations, but not considered to be continually under water. It is characterized by the growth of non woody plants and by the lack of trees.",2),
				new listedValue("Bog", "Wet spongy ground consisting of decaying vegetation, which retains stagnant water, too soft to bear the weight of any heavy body.",3),
				new listedValue("Heathland", "A tract of wasteland peat bog, usually covered by a low scrubby growth, but may have scattered small open water holes.",4),
				new listedValue("Mountain Range", "A series of connected and aligned mountains or mountain ridges.",5),
				new listedValue("Lowlands", "Low and relatively level land at a lower elevation than adjoining areas.",6),
				new listedValue("Canyon Lands", "A relatively narrow, deep depression with steep sides, the bottom of which generally has a continuous slope.",7),
				new listedValue("Paddy Field", "A piece of land set aside for crops which are periodically flooded (for example rice paddy).",8),
				new listedValue("Agricultural Land", "Of or pertaining to the science or practice of cultivating the soil and rearing animals.",9),
				new listedValue("Savanna/Grassland", "An open grassy plain with few or no trees in a tropical or subtropical region; a tract covered mainly by grasses that have little or no woody tissue.",10),
				new listedValue("Parkland", "A piece of ground kept for ornament and/or recreation or maintained in its natural state as a public property or area.",11),
				new listedValue("Swamp", "An area of spongy land saturated with water. It may have a shallow covering of water, usually with a considerable amount of vegetation appearing above the surface.",12),
				new listedValue("Landslide", "The sliding down of a mass of land on a mountain or cliff-side; land which has so fallen.",13),
				new listedValue("Lava Flow", "The substance that results from the cooling of molten rock.",14),
				new listedValue("Salt Pan", "Shallow pools of brackish water used for the natural evaporation of sea water to obtain salt.",15),
				new listedValue("Moraine", "Any accumulation of loose material deposited by a glacier.",16),
				new listedValue("Crater", "Bowl-shaped cavity, at the summit or on the side of a volcano.",17),
				new listedValue("Cave", "A natural subterranean chamber or series of chambers open to the earth's surface.",18),
				new listedValue("Rock Column or Pinnacle", "Any high tower or spire-shaped pillar of rock, alone or cresting a summit.",19),
				new listedValue("Cay", "A small insular feature usually with scant vegetation; usually of sand or coral. Often applied to smaller coral shoals.",20),
				new listedValue("Wadi", "A watercourse that is permanently dry or dry except for the rainy season.",21),
				new listedValue("Backshore", "That part of a beach which is usually dry, being reached only by the highest tides. Also called backbeach. See also ForeshoreE.",22),
				new listedValue("Beach", "On a shore, the area on which the waves break and over which shore debris, such as sand, shingle, pebbles accumulate. A beach includes backshore and foreshore.",23),
				new listedValue("Foreshore", "That part of shore which lies between high and low water mark at ordinary tide.",24),
			];

		public static implicit operator categoryOfLandRegion(int? value) => new categoryOfLandRegion { value = value };
	}

