				new listedValue("Continental Margin", "The zone, generally consisting of shelf, slope and continental rise, separating the continent from the deep seafloor or abyssal plain or plain. Occasionally a trench may be present in place of a continental rise.",28),
				new listedValue("Continental Rise", "A gentle slope rising from the oceanic depths towards the foot of a continental slope.",29),
				new listedValue("Escarpment", "An elongated, characteristically linear, steep slope separating horizontal or gently sloping areas of the seafloor.",30),
				new listedValue("Fan", "A relatively smooth, depositional feature continuously deepening away from a sediment source commonly located at the lower termination of a canyon or canyon system.",31),
				new listedValue("Fracture Zone", "A long narrow zone of irregular topography formed by the movement of tectonic plates associated with an offset of a spreading ridge axis, characterized by steep-sided and/or asymmetrical ridges, troughs or escarpments.",32),
				new listedValue("Gap", "A narrow break in a ridge, rise or other elevation.",33),
				new listedValue("Guyot", "A seamount having a comparatively smooth flat top.",34),
				new listedValue("Hill", "[1]  A small isolated elevation, smaller than a mountain.  [2]  A distinct elevation generally of irregular shape, less than 1000m above the surrounding relief as measured from the deepest isobath that surrounds most of the feature.",35),
				new listedValue("Hole", "A depression of limited extent with all sides rising steeply from a relatively flat bottom.",36),
				new listedValue("Levee", "A depositional embankment bordering a canyon, valley or sea channel.",37),
				new listedValue("Median Valley", "The axial depression of the mid-oceanic ridge system.",38),
				new listedValue("Moat", "An annular or partially annular depression commonly located at the base of seamounts, islands and other isolated elevations.",39),
				new listedValue("Mountains", "A natural elevation of the earth's surface rising more or less abruptly from the surrounding level, and attaining an altitude which, relatively to adjacent elevations, is impressive or notable.",40),
				new listedValue("Peak", "A conical or pointed elevation on a larger feature such as a seamount.",41),
				new listedValue("Province", "A geographically distinct region with a number of shared physiographic characteristics that contrast with those in the surrounding areas. This term should be modified with the generic term that best describes the majority of features in the region, for example \"Seamount\" in Baja California Seamount Province.",42),
				new listedValue("Rise", "A broad elevation that generally rises gently and smoothly from the surrounding relief.",43),
