				new listedValue("Shuga/Small Ice Cake; Brash Ice (2 m Across)", "An accumulation of spongy white ice lumps, a few centimetres across; they are formed from grease ice or slush and sometimes from anchor ice rising to the surface. Accumulations of floating ice made up of fragments not more than 2 m across, the wreckage of other forms of ice.",2),
				new listedValue("Ice Cake (20 m Across)", "Any relatively flat piece of sea ice less than 20 m across.",3),
				new listedValue("Small Floe (20 to 100 m Across)", "Any contiguous piece of sea ice, from 20 to 100 metres across.",4),
				new listedValue("Medium Floe (100 to 500 m Across)", "A relatively flat piece of sea ice 100 m to 500 m across. Floes are subdivided according to horizontal extent.",5),
