				new listedValue("Vast Floe (2000 to 10000 m Across)", "Any contiguous piece of sea ice, 2-10 kilometres across.",7),
				new listedValue("Giant Floe (10000 m Across)", "A relatively flat piece of sea ice 10 km or more across.",8),
				new listedValue("Fast Ice", "Sea ice which remains fast, generally in the position where originally formed, and which may attain a considerable thickness. It is found along coasts, where it is attached to the shore, or over shoals, where it may be held in position by islands, grounded icebergs or grounded polar ice.",9),
				new listedValue("Growlers, Floebergs or Floebits", "Growler: A smaller piece of ice of land origin than a bergy bit. The color is usually white, but sometimes transparent or blue-green or nearly black, normally occupying an area of about 20 m2 . Growlers are distinguished with difficulty when they are surrounded by ice and also in heavy swell.  Floeberg: A massive piece of sea ice composed of a hummock, or a group of hummocks frozen together, presenting a separate floating ice fragment in ice-free water or among separate ice fragments. It may protrude up to 5 m above sea-level.",10),
				new listedValue("Icebergs", "Massive pieces of ice of varying shape, protruding more than 5 m above sea-level, which have broken away from a glacier or an ice shelf, and which may be afloat or aground. Icebergs by their external look may be subdivided into tabular, dome-shaped, sloping and rounded bergs.",11),
				new listedValue("Undetermined/Unknown", "Having an unknown value.",99),
			];

