	/// <summary>
	/// Classification of shoreline construction based on use.
	/// </summary>
	public class categoryOfShorelineConstruction : S100FC.EnumerationAttribute
	{
		[JsonIgnore]
		public override string S100FC_code => nameof(categoryOfShorelineConstruction);
		[JsonIgnore]
		public override string S100FC_name => "Category of Shoreline Construction";
		public static listedValue[] listedValues => [
				new listedValue("Breakwater", "A structure protecting a shore area, harbour, anchorage, or basin from waves.",1),
				new listedValue("Groyne", "A low artificial wall-like structure of durable material extending from the land to seaward for a particular purpose, such as to protect the coast or to force a current to scour a channel.",2),
				new listedValue("Mole", "A form of breakwater alongside which vessels may lie on the sheltered side only; in some cases it may lie entirely within an artificial harbour, permitting vessels to lie along both sides.",3),
				new listedValue("Pier (Jetty)", "A long, narrow structure extending into the water to afford a berthing place for vessels, to serve as a promenade, etc.",4),
				new listedValue("Promenade Pier", "A pier built only for recreational purposes.",5),
				new listedValue("Wharf", "A structure serving as a berthing place for vessels.",6),
				new listedValue("Training Wall", "A wall or bank, often submerged, built to direct or confine the flow of a river or tidal current, or to promote a scour action.",7),
				new listedValue("Rip Rap", "A layer of broken rock, cobbles, boulders, or fragments of sufficient size to resist the erosive forces of flowing water and wave action.",8),
				new listedValue("Revetment", "Facing of stone or other material, either permanent or temporary, placed along the edge of a stream, river or canal to stabilize the bank and to protect it from the erosive action of the stream.",9),
				new listedValue("Sea Wall", "An embankment or wall for protection against waves or tidal action along a shore or water front.",10),
				new listedValue("Landing Steps", "Steps at the shoreline as the connection between land and water on different levels.",11),
				new listedValue("Ramp", "(1) A sloping structure which may include rails that can either be used, as a landing place, at variable water levels, for small vessels, landing ships, or a ferry boat, or for hauling a cradle carrying a vessel. (2) An accumulation of snow that forms an inclined plane between land or land ice elements and sea ice or ice shelf. Also called drift ice foot.",12),
				new listedValue("Slipway", "The prepared and usually reinforced inclined surface on which keel- and bilge-blocks are laid for supporting a vessel under construction.",13),
				new listedValue("Fender", "A protective structure designed to cushion the impact of a vessel and prevent damage.",14),
				new listedValue("Solid Face Wharf", "A wharf consisting of a solid wall of concrete, masonry, wood etc., such that the water cannot circulate freely under the wharf. The type of construction affects ship-handling; for example, a solid face wharf may give shelter from tidal streams, but under certain circumstances a cushion of water may build up between such a wharf and a ship attempting to berth at it, causing difficulties in ship handling.",15),
				new listedValue("Open Face Wharf", "A wharf supported on piles or other structures which allow free circulation of water under the wharf.",16),
				new listedValue("Log Ramp", "An inclined plane used to dump logs into the water for transport, or to haul logs out of the water for processing.",17),
				new listedValue("Swimming Facility", "An artificial pool or swimming enclosure, especially one in the open air, which may be constructed of wire mesh or heavy netting supported by cables, buoys or piles, for swimming in.",20),
				new listedValue("Quay", "A wharf approximately parallel to the shoreline and accommodating ships on one side only, the other side being attached to the shore. It is usually of solid construction, as contrasted with the open pile construction usually used for piers.",22),
				new listedValue("Tie-Up Wall", "A section of wall designated for tying-up vessels awaiting transit. Bollards and mooring devices are available for both large and small ships.",23),
				new listedValue("Artificial Obstacle", "Man-made structure that acts as an obstacle to landing operations.",501),
